import React, { useState, useCallback, useEffect, useMemo, useRef } from 'react';
import { useLocation } from 'react-router-dom';
import {
  Select,
  dispatchAppToast,
  LinErpListFilterBar,
  loadErpReportDisplayConfig,
  useServerPagedListLoading,
  LinReportPeriodSelectorFields,
  computeReportPeriodDates,
  nowMonth,
  nowYear,
  nowQuarter,
  yearOptionsFromStartYear,
  type ErpReportDisplayConfig,
  type ViewMode,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { AccountSummaryLineDto, ReportChartOptionDto } from '../../../services/kt/models';
import { reportPageLabels } from '../../../constants/reportPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { buildMonthYearPrintFilterLines } from '../../../utils/reportPrintFilters';
import {
  AccountSummaryReportGrid,
  ServerPagedAggregateReportShell,
  normalizeAggregateReportResponse,
} from '../../../components/report';
import type { LedgerChartData } from '../../../components/report/buildLedgerChartData';
import {
  getSoTongHopPageSession,
  reportPageSessionKey,
  saveSoTongHopPageSession,
} from '../../../components/report/reportPageSessionCache';
import { buildReportChartQueryParams } from '../../../utils/buildReportChartQueryParams';
import { isReportChartConfigChanged } from '../../../utils/erpReportChartPrefs';
import { selectPlaceholderClass } from '../../../utils/selectField';
import {
  DEFAULT_PAGE_SIZE,
  type ListPageSize,
} from '../../../components/list/VoucherListPagination';

const labels = reportPageLabels.soTongHop;
const TEST_ID = 'erp-so-tong-hop';
const PAGE_ID = 'kt-so-tong-hop';

const LEVEL_OPTIONS = [
  { value: '', label: labels.fieldLevelAll },
  ...([1, 2, 3, 4, 5, 6, 7, 8, 9].map(n => ({
    value: String(n),
    label: String(n),
  }))),
];

const chartLabels = {
  title: labels.chartTitle,
  kpiTotalDebit: labels.chartKpiTotalDebit,
  kpiTotalCredit: labels.chartKpiTotalCredit,
  kpiClosingBalance: labels.chartKpiClosingBalance,
  kpiClosingBalanceDebit: labels.chartKpiClosingBalanceDebit,
  kpiClosingBalanceCredit: labels.chartKpiClosingBalanceCredit,
  kpiEntryCount: labels.chartKpiEntryCount,
  seriesDebit: labels.chartSeriesDebit,
  seriesCredit: labels.chartSeriesCredit,
  seriesBalanceDebit: labels.chartSeriesBalanceDebit,
  seriesBalanceCredit: labels.chartSeriesBalanceCredit,
  viewFull: labels.chartViewFull,
  empty: labels.chartEmpty,
  noCharts: labels.chartNoTypes,
};

const configLabels = {
  configModalTitle: labels.configModalTitle,
  configSectionGrid: labels.configSectionGrid,
  configSectionFooter: labels.configSectionFooter,
  configSectionPrint: labels.configSectionPrint,
  configPrintBatchSizeLabel: labels.configPrintBatchSizeLabel,
  configPrintBatchSizeHint: labels.configPrintBatchSizeHint,
  configSectionChart: labels.configSectionChart,
  configChartEmptyHint: labels.configChartEmptyHint,
  printModalTitle: labels.printModalTitle,
  printScopeLabel: labels.printScopeLabel,
  printCurrentPageOption: labels.printCurrentPageOption,
  printAllPagesOption: labels.printAllPagesOption,
  printCancel: labels.printCancel,
  printConfirm: labels.printConfirm,
  printFetchHint: labels.printFetchHint,
  printScopeFilterLabel: labels.printScopeFilterLabel,
  printScopeCurrentValue: labels.printScopeCurrentValue,
  printScopeAllValue: labels.printScopeAllValue,
  chartNoTypes: labels.chartNoTypes,
};

type AppliedFilters = {
  viewMode: ViewMode;
  month: string;
  year: string;
  quarter: string;
  level: string;
  fromDate: string;
  toDate: string;
};

const SoTongHopPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const location = useLocation();
  const sessionKey = reportPageSessionKey(location.pathname, location.search);
  const cached = getSoTongHopPageSession(sessionKey);
  const displayConfigRef = useRef<ErpReportDisplayConfig>(loadErpReportDisplayConfig(TEST_ID));

  // Year options from env VITE_START_YEAR
  const startYear = import.meta.env.VITE_START_YEAR ? Number(import.meta.env.VITE_START_YEAR) : undefined;
  const yearOptions = startYear ? yearOptionsFromStartYear(startYear) : undefined;

  // ── Period state ──
  const [viewMode, setViewMode] = useState<ViewMode>(cached?.viewMode ?? 'month');
  const [month, setMonth] = useState(cached?.month ?? nowMonth());
  const [year, setYear] = useState(cached?.year ?? nowYear());
  const [quarter, setQuarter] = useState(cached?.quarter ?? nowQuarter());
  const [level, setLevel] = useState(cached?.level ?? '');

  // Computed dates based on view mode
  const computedDates = useMemo(
    () => {
      if (viewMode === 'year') {
        const y = Number(year);
        return { fromDate: `${y}-01-01`, toDate: `${y}-12-31` };
      }
      return computeReportPeriodDates(viewMode, month, year, quarter);
    },
    [viewMode, month, year, quarter],
  );

  // In day mode, parent manages fromDate/toDate directly via date range fields
  // In month/quarter mode, fromDate/toDate are computed
  const [manualFromDate, setManualFromDate] = useState(cached?.fromDate ?? '');
  const [manualToDate, setManualToDate] = useState(cached?.toDate ?? '');

  const fromDate = viewMode === 'day' ? manualFromDate : computedDates.fromDate;
  const toDate = viewMode === 'day' ? manualToDate : computedDates.toDate;

  // ── Grid state ──
  const [items, setItems] = useState<AccountSummaryLineDto[]>(cached?.items ?? []);
  const [page, setPage] = useState(cached?.page ?? 1);
  const [pageSize, setPageSize] = useState<ListPageSize>((cached?.pageSize as ListPageSize) ?? DEFAULT_PAGE_SIZE);
  const [totalCount, setTotalCount] = useState(cached?.totalCount ?? cached?.items?.length ?? 0);
  const [allowedCharts, setAllowedCharts] = useState<ReportChartOptionDto[]>([]);
  const [reportChartData, setReportChartData] = useState<LedgerChartData | null>(null);
  const {
    filterLoading,
    pageLoading,
    setLoadingMode,
    beginFetch,
    endFetch,
  } = useServerPagedListLoading();
  const [appliedFilters, setAppliedFilters] = useState<AppliedFilters | null>(null);

  const buildFetchParams = useCallback(
    (
      targetPage: number,
      targetPageSize: number,
      config: ErpReportDisplayConfig,
      charts: ReportChartOptionDto[],
      withChart: boolean,
    ) => {
      const chartQuery = withChart ? buildReportChartQueryParams(config, charts) : { includeChartData: false };
      return {
        fromDate,
        toDate,
        level: level ? Number(level) : undefined,
        page: targetPage,
        pageSize: config.showFooterPagination ? targetPageSize : 0,
        ...chartQuery,
      };
    },
    [fromDate, toDate, level],
  );

  const fetchPage = useCallback(
    async (
      targetPage: number,
      mode: 'load' | 'page' = 'load',
      overrideConfig?: ErpReportDisplayConfig,
      overrideCharts?: ReportChartOptionDto[],
    ) => {
      const config = overrideConfig ?? displayConfigRef.current;
      const charts = overrideCharts ?? allowedCharts;
      const withChart = mode === 'load';
      setLoadingMode(mode === 'load' ? 'filter' : 'page');
      beginFetch();

      try {
        const raw = await ktService.getAccountSummary(
          buildFetchParams(targetPage, pageSize, config, charts, withChart),
        );
        const report = normalizeAggregateReportResponse<AccountSummaryLineDto>(raw);
        setItems(report.items);
        if (mode === 'load') {
          setAllowedCharts(report.charts);
          setReportChartData(report.chartData);
        }
        setTotalCount(report.totalCount);
        setPage(report.page);
        setAppliedFilters({ viewMode, month, year, quarter, level, fromDate, toDate });
        saveSoTongHopPageSession(sessionKey, {
          viewMode,
          month,
          year,
          quarter,
          level,
          fromDate,
          toDate,
          items: report.items,
          totalCount: report.totalCount,
          page: report.page,
          pageSize,
        });
      } catch (err) {
        dispatchAppToast(dispatch, { message: getApiErrorMessage(err, labels.loadError), type: 'error' });
        throw err;
      } finally {
        endFetch();
      }
    },
    [allowedCharts, buildFetchParams, dispatch, fromDate, level, month, pageSize, sessionKey, setLoadingMode, beginFetch, endFetch, toDate, year, viewMode, quarter],
  );

  const handleLoad = useCallback(() => {
    setPage(1);
    fetchPage(1, 'load').catch(() => undefined);
  }, [fetchPage]);

  // Auto-load when period/level filter changes
  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      if (!cancelled && fromDate && toDate) {
        setPage(1);
        fetchPage(1, 'load').catch(() => undefined);
      }
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps -- auto-load when filter changes
  }, [fromDate, toDate, level]);

  const handlePageChange = useCallback(
    (nextPage: number) => {
      if (!appliedFilters || pageLoading) return;
      const prev = page;
      setPage(nextPage);
      fetchPage(nextPage, 'page').catch(() => setPage(prev));
    },
    [appliedFilters, pageLoading, page, fetchPage],
  );

  const handlePageSizeChange = useCallback(
    (nextPageSize: ListPageSize) => {
      setPageSize(nextPageSize);
      setPage(1);
      if (!appliedFilters || !displayConfigRef.current) return;
      setLoadingMode('filter');
      beginFetch();
      ktService
        .getAccountSummary(
          buildFetchParams(1, nextPageSize, displayConfigRef.current, allowedCharts, true),
        )
        .then(raw => {
          const report = normalizeAggregateReportResponse<AccountSummaryLineDto>(raw);
          setItems(report.items);
          setAllowedCharts(report.charts);
          setReportChartData(report.chartData);
          setTotalCount(report.totalCount);
          setPage(report.page);
        })
        .catch(err =>
          dispatchAppToast(dispatch, { message: getApiErrorMessage(err, labels.loadError), type: 'error' }),
        )
        .finally(() => endFetch());
    },
    [appliedFilters, allowedCharts, buildFetchParams, dispatch, setLoadingMode, beginFetch, endFetch],
  );

  const handleConfigSaved = useCallback(
    (next: ErpReportDisplayConfig, prev: ErpReportDisplayConfig) => {
      displayConfigRef.current = next;
      const paginationChanged = next.showFooterPagination !== prev.showFooterPagination;
      const chartChanged = isReportChartConfigChanged(prev.chart, next.chart);
      if ((paginationChanged || chartChanged) && appliedFilters) {
        setPage(1);
        fetchPage(1, 'load', next, allowedCharts).catch(() => undefined);
      }
    },
    [appliedFilters, allowedCharts, fetchPage],
  );

  const printFilterLines = useMemo(
    () => (appliedFilters ? buildMonthYearPrintFilterLines(appliedFilters, labels) : []),
    [appliedFilters],
  );

  const fetchPrintPage = useCallback(
    async (targetPage: number, batchSize: number) => {
      if (!displayConfigRef.current) return [];
      const raw = await ktService.getAccountSummary(
        buildFetchParams(targetPage, batchSize, displayConfigRef.current, allowedCharts, false),
      );
      return normalizeAggregateReportResponse<AccountSummaryLineDto>(raw).items;
    },
    [allowedCharts, buildFetchParams],
  );

  // ── Xem theo handlers ──

  // Nếu user sửa date range trực tiếp → auto chuyển sang day mode
  const handleDateRangeChange = useCallback(
    (from?: string, to?: string) => {
      if (!from && !to) return;
      if (viewMode !== 'day') {
        setViewMode('day');
        // Giữ nguyên các giá trị period hiện tại, chỉ switch mode
      }
      if (from) setManualFromDate(from);
      if (to) setManualToDate(to);
    },
    [viewMode],
  );

  // Đổi chế độ xem: auto-fill kỳ
  const handleViewModeChange = useCallback(
    (mode: ViewMode) => {
      if (mode === viewMode) return;

      // Khi đổi sang day mode, fill date từ computed period hiện tại
      if (mode === 'day') {
        let from: string;
        let to: string;
        if (viewMode === 'year') {
          const y = Number(year);
          from = `${y}-01-01`;
          to = `${y}-12-31`;
        } else {
          const currentComputed = computeReportPeriodDates(viewMode, month, year, quarter);
          from = currentComputed.fromDate;
          to = currentComputed.toDate;
        }
        setManualFromDate(from);
        setManualToDate(to);
      } else {
        setManualFromDate('');
        setManualToDate('');
      }

      if (mode === 'month') {
        setMonth(nowMonth());
        setYear(nowYear());
      } else if (mode === 'quarter') {
        setQuarter(nowQuarter());
        setYear(nowYear());
      } else if (mode === 'year') {
        setYear(nowYear());
      }

      setViewMode(mode);
    },
    [viewMode, month, year, quarter],
  );

  const periodSelectorLabels = useMemo(
    () => ({
      viewMode: labels.fieldViewMode,
      fieldMonth: labels.fieldMonth,
      fieldYear: labels.fieldYear,
      fieldQuarter: labels.fieldQuarter,
    }),
    [],
  );

  const filters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={handleDateRangeChange}
        dateLabel={labels.fieldPeriod}
        onSearch={handleLoad}
        searchAriaLabel={labels.view}
        loading={filterLoading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-level`}>
              <Select
                label={labels.fieldLevel}
                id={`${TEST_ID}-level`}
                value={level}
                onChange={e => setLevel(e.target.value)}
                options={LEVEL_OPTIONS}
                className={selectPlaceholderClass(level)}
              />
            </div>
            <LinReportPeriodSelectorFields
              testIdPrefix={TEST_ID}
              labels={periodSelectorLabels}
              viewMode={viewMode}
              month={month}
              year={year}
              quarter={quarter}
              yearOptions={yearOptions}
              onViewModeChange={handleViewModeChange}
              onMonthChange={setMonth}
              onYearChange={setYear}
              onQuarterChange={setQuarter}
            />
          </>
        )}
      />
    ),
    [fromDate, toDate, handleDateRangeChange, handleLoad, filterLoading, periodSelectorLabels, viewMode, month, year, quarter, level, handleViewModeChange],
  );

  return (
    <ServerPagedAggregateReportShell
      testIdPrefix={TEST_ID}
      pageId={PAGE_ID}
      title={labels.title}
      listTitle={labels.listTitle}
      titleIconClass="fas fa-table"
      emptyMessage={labels.empty}
      filters={filters}
      items={items}
      totalCount={totalCount}
      page={page}
      pageSize={pageSize}
      hasApplied={appliedFilters != null}
      loading={filterLoading}
      pageLoading={pageLoading}
      onRefresh={handleLoad}
      onPageChange={handlePageChange}
      onPageSizeChange={handlePageSizeChange}
      onConfigSaved={handleConfigSaved}
      printFilterLines={printFilterLines}
      allowedCharts={allowedCharts}
      reportChartData={reportChartData}
      chartLabels={chartLabels}
      configLabels={configLabels}
      fetchPrintPage={fetchPrintPage}
      listRowMenuHelp
    >
      {(rows, { rowNo, onPrint, onChart, canChart }) => (
        <AccountSummaryReportGrid
          rows={rows}
          rowNo={rowNo}
          labels={{
            colNo: labels.colNo,
            colAccount: labels.colAccount,
            colName: labels.colName,
            colDebit: labels.colDebit,
            colCredit: labels.colCredit,
            rowMenuViewReportDetail: labels.rowMenuViewReportDetail,
            rowMenuRefreshData: labels.rowMenuRefreshData,
            rowMenuPrint: labels.rowMenuPrint,
            rowMenuExport: labels.rowMenuExport,
            rowMenuChart: labels.rowMenuChart,
            rowMenuHint: labels.rowMenuHint,
            rowMenuHintTouch: labels.rowMenuHintTouch,
          }}
          testIdPrefix={TEST_ID}
          onRefresh={handleLoad}
          onPrint={onPrint}
          onChart={onChart}
          canChart={canChart}
          detailReportTitle={reportPageLabels.soChiTiet.title}
          reportTitle={labels.title}
        />
      )}
    </ServerPagedAggregateReportShell>
  );
};

export default SoTongHopPage;
